const Web3 = require('web3');
const ethers = require('ethers');

// Set up provider (e.g., Infura, Alchemy)
const provider = new ethers.providers.JsonRpcProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID');

// Define token addresses and DEX contract address
const token1Address = '0x...'; // Token 1 address
const token2Address = '0x...'; // Token 2 address
const dexContractAddress = '0x...'; // DEX contract address

// Set up wallet (e.g., MetaMask)
const wallet = new ethers.Wallet('YOUR_PRIVATE_KEY', provider);

// Define functions for token approval and swapping
async function approveToken(tokenAddress, amount) {
    const tokenContract = new ethers.Contract(tokenAddress, [
        'function approve(address spender, uint256 amount) public',
    ], wallet);
    await tokenContract.approve(dexContractAddress, amount);
}

async function swapTokens(token1Amount, token2Amount) {
    // Get DEX contract instance
    const dexContract = new ethers.Contract(dexContractAddress, [
        'function swapTokens(address token1, address token2, uint256 token1Amount, uint256 token2Amount)',
    ], wallet);

    // Approve tokens for swapping (if not already approved)
    await approveToken(token1Address, ethers.constants.MaxUint256);
    await approveToken(token2Address, ethers.constants.MaxUint256);

    // Swap tokens
    const tx = await dexContract.swapTokens(
        token1Address,
        token2Address,
        token1Amount,
        token2Amount,
    );
    return tx;
}

